"use client"
import React, { useState } from 'react'
import '../../../css/home/main.css'
import Link from 'next/link';
import axios from 'axios';

const page = () => {

  const handleTestMessage = async () => {
    const token = localStorage.getItem('token'); // 로그인 토큰
    if (!token) return alert("로그인이 필요합니다.");

    try {
      await axios.post('http://localhost:8080/api/notification/test/self', {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert("카톡을 확인해보세요! 📩");
    } catch (error) {
      console.error(error);
      alert("전송 실패! 백엔드 로그를 확인하세요.");
    }
  };
  
 return (
    <div className="pharmacy-container">
      {/* header */}


      {/* Hero Section */}
      <section className="hero-section">
        <div className="container hero-content">
          <div className="hero-text">
            <h1>
              당신의 건강을 위한 <br /> 
              <span className="highlight">가장 빠른 처방전</span>
            </h1>
            <p>
              최신 의약품 정보부터 내 주변 24시 약국까지, <br />
              다약과 함께 똑똑하게 건강을 관리하세요.
            </p>
            <div className="hero-buttons">
               {/* /store/location */}
               <Link href="/store/location">
                <button className="primary-btn">약국 찾기</button>
               </Link>
              
            </div>
          </div>
          <div className="hero-image">
            {/* <button 
  onClick={handleTestMessage}
  style={{ padding: '10px 20px', backgroundColor: '#FEE500', color: '#000', borderRadius: '5px', fontWeight: 'bold' }}
>
  카카오톡 알림 테스트 🔔
</button> */}
          </div>
        </div>
      </section>

      {/* 2. [NEW] 퀵메뉴 (정사각형 4개) */}
      <section className="quick-menu-section">
        <div className="container">
          <h2 className="section-title">빠른 메뉴</h2>
          <div className="quick-grid">
            {/* 메뉴 1 */}
            <Link href="/store/location" className="quick-item">
              <img 
                src="img/home/h2.png"
                alt="약국 찾기" 
              />
              <div className="quick-overlay">
                <h3>약국 찾기</h3>
                <p>내 주변 가까운 약국</p>
              </div>
            </Link>

            {/* 메뉴 2 */}
            <Link href="/drug" className="quick-item">
              <img 
                src="img/home/h1.png"
                alt="통합검색" 
              />
              <div className="quick-overlay">
                <h3>일반 의약품검색</h3>
                <p>일반의약품 검색</p>
              </div>
            </Link>

            {/* 메뉴 3 */}
            <Link href="/pill" className="quick-item">
              <img 
                src="img/home/h3.png"
                alt="상세검색" 
              />
              <div className="quick-overlay">
                <h3>식별검색</h3>
                <p>의약품 식별검색</p>
              </div>
            </Link>

            {/* 메뉴 4 */}
            <Link href="/board" className="quick-item">
              <img 
                src="img/home/h4.png"
                alt="식별검색" 
              />
              <div className="quick-overlay">
                <h3>자유게시판</h3>
                <p>자유게시판</p>
              </div>
            </Link>
          </div>
        </div>
      </section>


     {/* 3. Services Section (제공 서비스) - 필요 없다면 삭제 가능 */}
      <section className="services-section">
        <div className="container">
          <h2 className="section-title">제공 서비스</h2>
          <div className="services-grid">
            <Link href={'/medication/calender'}>
            <div className="service-card">
              <div className="icon-box bg-blue">💪</div>
              <h3>복약 달력</h3>
              <p>복약 체크 달력</p>
            </div>
            </Link>
            <Link href={'/medication/list'}>
            <div className="service-card">
              <div className="icon-box bg-yellow">⏰</div>
              <h3>복약 리스트</h3>
              <p>복용 시간 체크</p>
            </div>
            </Link>
            <Link href={"/twoalarm"}>
            <div className="service-card">
              <div className="icon-box bg-red">🏥</div>
              <h3>보호자 복약 알림기능</h3>
              <p>보호자 연동 알림기능</p>
            </div>
            </Link>
          </div>
        </div>
      </section>

      {/* 4. 게시판 & 공지사항 미리보기 */}
      <section className="info-section">
        <div className="container info-grid">
          <div className="info-box">
            <h3>📢 공지사항</h3>
            <ul>
              <li>[공지] 서비스 점검 안내 (02/10)</li>
              <li>[이벤트] 신규 가입 이벤트 안내</li>
              <li>[업데이트] 검색 기능 개선</li>
            </ul>
          </div>
          <div className="info-box">
            <h3>💡 건강 꿀팁</h3>
            <ul>
              <li>환절기 면역력 높이는 음식 5가지</li>
              <li>올바른 영양제 복용 순서</li>
              <li>눈 피로를 풀어주는 1분 스트레칭</li>
            </ul>
          </div>
        </div>
      </section>

      {/* Footer */}
    </div>
  );
};

export default page